const { Storage } = require('@google-cloud/storage');

exports.serveFile = async (req, res) => {
  const bucketName = req.query.bucket;
  const filePath = req.query.file;

  // Validate input
  if (!bucketName || !filePath) {
    return res.status(400).send('Invalid request');
  }

  // Get the storage client
  const storage = new Storage();

  // Get the file metadata
  const [metadata] = await storage.bucket(bucketName).file(filePath).getMetadata();

  // Check if the file exists and is publicly readable
  if (!metadata || !metadata.acl.readers.includes('allUsers')) {
    return res.status(403).send('Forbidden');
  }

  // Stream the file to the client
  const [stream] = await storage.bucket(bucketName).file(filePath).createReadStream();
  stream.pipe(res);
};